sys_script_email.script:
if (current.item_type == 'cmdb_ci_computer' && !current.cmdb_ci.nil()) {
    var request = new sn_ws.RESTMessageV2();
    request.setEndpoint('https://nowlearning-nlinst04026007-6wy4w-0001.lab.service-now.com/api/now/table/u_password_vault?sysparm_query=u_asset%3D' + current.cmdb_ci.asset_tag + '&sysparm_fields=u_password&sysparm_limit=1');
    request.setHttpMethod('GET');

	template.print('x_cdltd_loaner_r_0_loaner_request_script_1: Hard-coded REST client credentials!');
    var user = 'admin';
    var password = '2K9tHnRys9Mf';

	request.setBasicAuth(user, password);
    request.setRequestHeader("Accept", "application/json");

	var response = request.execute();
    // gs.info(response.getBody());

    // {"result":[]}   OR   {"result":[{"u_password":"earth"}]}
    var { result } = JSON.parse(response.getBody());
    if (result && result.length) {
        var { u_password } = result[0];

        template.print('x_cdltd_loaner_r_0_loaner_request_script_1: Clear text passwords!');
        template.print('<p>Password = ' + u_password + '</p>');
    }
}
